$toolDefinition_website_change_monitor = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'website_change_monitor',
    'description' => 'Monitor web pages for content changes across tool calls. Fetches one or more URLs, computes content hashes, persists state in SQLite, and reports what changed since the last check. Stores full content history (with size limits) and previous diff snapshots. Can optionally email alerts via SMTP when changes are detected. Composes http_fetch + text_diff + SQLite for unattended web monitoring. First persistent web monitoring tool in the ecosystem — runs across sessions without human intervention. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'urls' => 
        array (
          'type' => 'array',
          'description' => 'Array of URLs to monitor. Required on first call (to set up monitoring). Subsequent calls can omit to check all stored URLs.',
          'items' => 
          array (
            'type' => 'string',
          ),
