if (! function_exists('website_change_monitor')) {
    function website_change_monitor($urls = null, $db_name = null, $timeout = null, $max_content_bytes = null, $body_limit = null, $mode = null, $url = null, $force_refresh = null)
    {
        // Website Change Monitor — unattended web page change detection
        // Persists content hashes and change history in SQLite

        $dbName = $db_name ?? 'web_monitor.sqlite';
        $dbPath = __DIR__ . '/../workspace/' . $dbName;
        $mode = $mode ?? 'check';
        $timeout = min(30, max(5, $timeout ?? 15));
        $maxContentBytes = min(1048576, max(1024, $max_content_bytes ?? 65536));
        $bodyLimit = min(1048576, max(1024, $body_limit ?? 262144));
        $forceRefresh = $force_refresh ?? false;

        try {
            // Ensure workspace directory exists
            $workspaceDir = __DIR__ . '/../workspace';
            if (!is_dir($workspaceDir)) {
                mkdir($workspaceDir, 0755, true);
            }

            $db = new PDO("sqlite:$dbPath");
            $db->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            $db->exec("CREATE TABLE IF NOT EXISTS monitored_urls (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                url TEXT UNIQUE NOT NULL,
                label TEXT,
                content_hash TEXT,
                content_snippet TEXT,
                last_status INTEGER,
                last_checked TEXT,
                first_seen TEXT DEFAULT (datetime('now')),
                active INTEGER DEFAULT 1
            )");
            $db->exec("CREATE TABLE IF NOT EXISTS change_history (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                url TEXT NOT NULL,
                change_type TEXT NOT NULL,  -- 'first_seen', 'content_changed', 'status_changed', 'error'
                old_hash TEXT,
                new_hash TEXT,
                old_status INTEGER,
                new_status INTEGER,
                error_message TEXT,
                diff_snippet TEXT,
                seen_at TEXT DEFAULT (datetime('now'))
            )");

            // --- MODE: list ---
            if ($mode === 'list') {
                $stmt = $db->query("SELECT url, label, content_hash, last_status, last_checked, first_seen, active FROM monitored_urls ORDER BY url");
                $urls = [];
                while ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {
                    $urls[] = $row;
                }
                return ['success' => true, 'mode' => 'list', 'monitored_urls' => $urls, 'count' => count($urls)];
            }

            // --- MODE: add ---
            if ($mode === 'add') {
                if (empty($urls)) {
                    return ['success' => false, 'error' => 'URLs array is required for add mode.', 'mode' => 'add'];
                }
                $added = 0;
                $errors = [];
                foreach ($urls as $url) {
                    if (!filter_var($url, FILTER_VALIDATE_URL)) {
                        $errors[] = "Invalid URL: $url";
                        continue;
                    }
                    try {
                        // Fetch the URL for initial snapshot
                        $ctx = stream_context_create([
                            'http' => [
                                'method' => 'GET',
                                'timeout' => $timeout,
                                'header' => "User-Agent: WebsiteChangeMonitor/1.0\r\nAccept: text/html,application/json,*/*\r\n",
                                'ignore_errors' => true,
                            ],
                            'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                        ]);
                        $body = @file_get_contents($url, false, $ctx);
                        $httpCode = 0;
                        if (isset($http_response_header)) {
                            preg_match('/HTTP\/\d\.\d\s+(\d+)/', $http_response_header[0], $m);
                            $httpCode = (int)($m[1] ?? 0);
                        }
                        $contentHash = $body !== false ? md5($body) : 'error_' . md5(time() . $url);
                        $snippet = $body !== false ? mb_substr($body, 0, 500, 'UTF-8') : 'Failed to fetch';

                        $stmt = $db->prepare("INSERT OR REPLACE INTO monitored_urls (url, label, content_hash, content_snippet, last_status, last_checked) VALUES (?, ?, ?, ?, ?, datetime('now'))");
                        $label = $label ?? parse_url($url, PHP_URL_HOST) ?: $url;
                        $stmt->execute([$url, $label, $contentHash, $snippet, $httpCode]);
                        $added++;

                        // Record as first_seen in history
                        $hist = $db->prepare("INSERT INTO change_history (url, change_type, new_hash, new_status, diff_snippet) VALUES (?, 'first_seen', ?, ?, ?)");
                        $hist->execute([$url, $contentHash, $httpCode, $snippet]);
                    } catch (\Exception $e) {
                        $errors[] = "$url: " . $e->getMessage();
                    }
                }
                $result = ['success' => true, 'mode' => 'add', 'urls_added' => $added];
                if (!empty($errors)) {
                    $result['errors'] = $errors;
                }
                return $result;
            }

            // --- MODE: remove ---
            if ($mode === 'remove') {
                if (empty($url)) {
                    return ['success' => false, 'error' => 'URL parameter required for remove mode.', 'mode' => 'remove'];
                }
                $stmt = $db->prepare("UPDATE monitored_urls SET active = 0 WHERE url = ?");
                $stmt->execute([$url]);
                if ($stmt->rowCount() > 0) {
                    return ['success' => true, 'mode' => 'remove', 'url' => $url, 'removed' => true];
                }
                return ['success' => true, 'mode' => 'remove', 'url' => $url, 'removed' => false, 'note' => 'URL was not in monitoring list.'];
            }

            // --- MODE: reset ---
            if ($mode === 'reset') {
                if (!empty($url)) {
                    $stmt = $db->prepare("UPDATE monitored_urls SET content_hash = NULL, content_snippet = NULL WHERE url = ?");
                    $stmt->execute([$url]);
                    $count = $stmt->rowCount();
                } else {
                    $count = $db->exec("UPDATE monitored_urls SET content_hash = NULL, content_snippet = NULL");
                }
                return ['success' => true, 'mode' => 'reset', 'urls_reset' => $count];
            }

            // --- MODE: history ---
            if ($mode === 'history') {
                if (empty($url)) {
                    return ['success' => false, 'error' => 'URL parameter required for history mode.', 'mode' => 'history'];
                }
                $stmt = $db->prepare("SELECT * FROM change_history WHERE url = ? ORDER BY seen_at DESC LIMIT 50");
                $stmt->execute([$url]);
                $history = [];
                while ($row = $stmt->fetch(PDO::FETCH_ASSOC)) {
                    $history[] = $row;
                }
                return ['success' => true, 'mode' => 'history', 'url' => $url, 'history' => $history, 'changes_detected' => count($history)];
            }

            // --- MODE: check (default) ---
            // Get all active monitored URLs
            $stmt = $db->query("SELECT url, label, content_hash, last_status FROM monitored_urls WHERE active = 1 ORDER BY url");
            $monitored = $stmt->fetchAll(PDO::FETCH_ASSOC);

            if (empty($monitored)) {
                return ['success' => true, 'mode' => 'check', 'note' => 'No URLs are being monitored. Use mode:add to add URLs first.', 'checked' => 0, 'changed' => 0, 'results' => []];
            }

            // If specific URLs provided, filter to just those
            if (!empty($urls)) {
                $urlSet = array_flip($urls);
                $monitored = array_filter($monitored, function($m) use ($urlSet) {
                    return isset($urlSet[$m['url']]);
                });
            }

            $results = [];
            $changedCount = 0;
            $errorCount = 0;

            foreach ($monitored as $entry) {
                $url = $entry['url'];
                $oldHash = $entry['content_hash'];

                try {
                    $ctx = stream_context_create([
                        'http' => [
                            'method' => 'GET',
                            'timeout' => $timeout,
                            'header' => "User-Agent: WebsiteChangeMonitor/1.0\r\nAccept: text/html,application/json,*/*\r\n",
                            'ignore_errors' => true,
                        ],
                        'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                    ]);
                    $startTime = microtime(true);
                    $body = @file_get_contents($url, false, $ctx);
                    $elapsed = (microtime(true) - $startTime) * 1000;

                    $httpCode = 0;
                    $headers = [];
                    if (isset($http_response_header)) {
                        $headers = $http_response_header;
                        preg_match('/HTTP\/\d\.\d\s+(\d+)/', $headers[0], $m);
                        $httpCode = (int)($m[1] ?? 0);
                    }

                    // Truncate body for storage
                    $bodyTruncated = $body !== false ? mb_substr($body, 0, $bodyLimit, 'UTF-8') : '';

                    // Compute content hash (only from the meaningful content, not full body to avoid huge diffs)
                    $meaningful = $body !== false ? preg_replace('/\s+/', ' ', substr($bodyTruncated, 0, $maxContentBytes)) : '';
                    $newHash = $body !== false ? md5($meaningful) : 'fetch_failed';

                    $changeType = 'no_change';
                    $diffSnippet = null;

                    if ($oldHash === null || $forceRefresh) {
                        // First snapshot or forced refresh
                        $changeType = 'snapshot_taken';
                        $snippetStore = mb_substr($bodyTruncated, 0, $maxContentBytes);
                        $hist = $db->prepare("INSERT INTO change_history (url, change_type, new_hash, new_status, diff_snippet) VALUES (?, 'snapshot_taken', ?, ?, ?)");
                        $hist->execute([$url, $newHash, $httpCode, mb_substr($bodyTruncated, 0, 1000)]);
                    } elseif ($newHash !== $oldHash) {
                        // Content changed!
                        $changeType = 'content_changed';
                        $changedCount++;
                        // Generate diff snippet using simple line comparison
                        $oldSnippet = $entry['content_snippet'] ?? '';
                        $oldLines = explode("\n", $oldSnippet);
                        $newLines = explode("\n", mb_substr($bodyTruncated, 0, $maxContentBytes));
                        // Find first differing line
                        $firstDiff = null;
                        $maxCheck = min(count($oldLines), count($newLines), 200);
                        for ($i = 0; $i < $maxCheck; $i++) {
                            if ($oldLines[$i] !== $newLines[$i]) {
                                $firstDiff = [
                                    'line' => $i + 1,
                                    'old' => mb_substr($oldLines[$i], 0, 200),
                                    'new' => mb_substr($newLines[$i], 0, 200),
                                ];
                                break;
                            }
                        }
                        $diffSnippet = $firstDiff;
                        $snippetStore = mb_substr($bodyTruncated, 0, $maxContentBytes);
                        $hist = $db->prepare("INSERT INTO change_history (url, change_type, old_hash, new_hash, old_status, new_status, diff_snippet) VALUES (?, 'content_changed', ?, ?, ?, ?, ?)");
                        $hist->execute([$url, $oldHash, $newHash, $entry['last_status'], $httpCode, json_encode($firstDiff)]);
                    } elseif ($httpCode !== (int)$entry['last_status']) {
                        // Status code changed
                        $changeType = 'status_changed';
                        $hist = $db->prepare("INSERT INTO change_history (url, change_type, old_status, new_status, diff_snippet) VALUES (?, 'status_changed', ?, ?, ?)");
                        $hist->execute([$url, $entry['last_status'], $httpCode, "Status changed from {$entry['last_status']} to $httpCode"]);
                    }

                    // Update stored state
                    $upd = $db->prepare("UPDATE monitored_urls SET content_hash = ?, content_snippet = ?, last_status = ?, last_checked = datetime('now') WHERE url = ?");
                    $upd->execute([$newHash, mb_substr($bodyTruncated, 0, $maxContentBytes), $httpCode, $url]);

                    $results[] = [
                        'url' => $url,
                        'label' => $entry['label'],
                        'status_code' => $httpCode,
                        'response_time_ms' => round($elapsed, 1),
                        'change_type' => $changeType,
                        'diff' => $diffSnippet,
                    ];
                } catch (\Exception $e) {
                    $errorCount++;
                    $results[] = [
                        'url' => $url,
                        'label' => $entry['label'],
                        'error' => $e->getMessage(),
                        'change_type' => 'error',
                    ];
                    // Log error to history
                    $hist = $db->prepare("INSERT INTO change_history (url, change_type, old_status, error_message) VALUES (?, 'error', ?, ?)");
                    $hist->execute([$url, $entry['last_status'] ?? null, $e->getMessage()]);
                }
            }

            return [
                'success' => true,
                'mode' => 'check',
                'checked' => count($results),
                'changed' => $changedCount,
                'errors' => $errorCount,
                'results' => $results,
            ];

        } catch (\Exception $e) {
            return ['success' => false, 'error' => $e->getMessage(), 'mode' => $mode];
        }
    }
}
